const agent = client.vm.getOrCreate(["my-agent"]);

// Queue overlapping executions
await agent.scheduleCron({
  schedule: "*/5 * * * *",
  overlap: "queue",
  action: {
    type: "session",
    agentType: "pi",
    prompt: "Process the next batch of tasks",
  },
});
